import { useQuery, useMutation } from '@tanstack/react-query';
import { useToast } from '@/hooks/use-toast';
import { apiRequest, queryClient } from '@/lib/queryClient';
import type { AutoGeneratedProject, MaintenanceProject } from '@shared/schemas/maintenance';

/**
 * Hook to fetch auto-generated projects for a building
 * @param buildingId - The building ID to fetch auto-projects for
 * @returns Query result with auto-generated projects data
 */
export function useAutoGeneratedProjects(buildingId?: string) {
  return useQuery({
    queryKey: ['/api/maintenance/buildings', buildingId, 'auto-projects'],
    queryFn: async () => {
      if (!buildingId) throw new Error('Building ID is required');
      const response = await apiRequest('GET', `/api/maintenance/buildings/${buildingId}/auto-projects`);
      return await response.json();
    },
    enabled: !!buildingId,
    staleTime: 2 * 60 * 1000, // 2 minutes
  });
}

/**
 * Hook to accept an auto-generated project and convert it to a real project
 * @returns Mutation function to accept auto-project
 */
export function useAcceptAutoProject() {
  const { toast } = useToast();
  
  return useMutation({
    mutationFn: async (data: { 
      autoProjectId: string; 
      buildingId: string;
      projectData?: {
        title?: string;
        description?: string;
        totalBudget?: number;
        plannedStartDate?: string;
        plannedEndDate?: string;
        vendorId?: string;
        priority?: string;
        type?: string;
      }
    }) => {
      const response = await apiRequest('POST', `/api/maintenance/auto-projects/${data.autoProjectId}/accept`, {
        buildingId: data.buildingId,
        ...data.projectData,
      });
      return await response.json();
    },
    onSuccess: (result, variables) => {
      // Invalidate both auto-projects and main projects lists
      queryClient.invalidateQueries({ 
        queryKey: ['/api/maintenance/buildings', variables.buildingId, 'auto-projects'] 
      });
      queryClient.invalidateQueries({ 
        queryKey: ['/api/maintenance/buildings', variables.buildingId, 'projects'] 
      });
      
      toast({
        title: "Project Created",
        description: "Auto-generated project has been accepted and converted to a maintenance project.",
      });
    },
    onError: (error) => {
      toast({
        title: "Accept Failed",
        description: "Failed to accept auto-generated project. Please try again.",
        variant: "destructive",
      });
      console.error('Auto-project accept failed:', error);
    },
  });
}

/**
 * Hook to edit an auto-generated project before accepting
 * @returns Mutation function to edit auto-project
 */
